class Regularizers():
    """
    Class for regularizers used in BaM
    """

    def __init__(self):

        self.counter = 0

    def reset(self):

        self.counter = 0


    def constant(self, reg0):

        def reg_iter(iteration):
            self.counter +=1
            return reg0
        return reg_iter


    def linear(self, reg0):

        def reg_iter(iteration):
            self.counter += 1
            return reg0/self.counter

        return reg_iter


    def custom(self, func):

        def reg_iter(iteration):
            self.counter += 1
            return func(self.counter)

        return reg_iter

